// Format and prepare posts for publishing
const aiContent = JSON.parse($input.first().json.message.content);
const trends = $('Fetch Industry Trends').first().json.trends;

const posts = [
  {
    platform: 'LinkedIn',
    content: aiContent.linkedin_post,
    image_idea: aiContent.suggested_image_idea,
    best_time: aiContent.best_posting_times.linkedin,
    status: 'pending_approval',
    created_at: $now.toISO()
  },
  {
    platform: 'Twitter',
    content: aiContent.twitter_post,
    image_idea: aiContent.suggested_image_idea,
    best_time: aiContent.best_posting_times.twitter,
    status: 'pending_approval',
    created_at: $now.toISO()
  },
  {
    platform: 'Instagram',
    content: aiContent.instagram_post,
    image_idea: aiContent.suggested_image_idea,
    best_time: aiContent.best_posting_times.instagram,
    status: 'pending_approval',
    created_at: $now.toISO()
  }
];

return posts.map(p => ({ json: { ...p, trends: trends } }));

